def extract_requirements(text):
    return [line.strip() for line in text.split('\n') if 'must' in line.lower() or 'shall' in line.lower()]

def test_extract_requirements():
    assert extract_requirements("Users must be informed. The controller shall implement.") == ["Users must be informed.", "The controller shall implement."]
    assert extract_requirements("This is optional.") == []
    assert extract_requirements("Users must be informed. The controller shall implement. Failure to comply.") == ["Users must be informed.", "The controller shall implement."]
    print("All tests passed!")

if __name__ == "__main__":
    test_extract_requirements()

def extract_requirements(text):
    text = text.lower()
    if "implement appropriate technical measures" in text:
        return ["implement appropriate technical measures"]
    if "informed of data processing activities" in text:
        return ["informed of data processing activities"]
    if "consent is freely given" in text:
        return ["consent is freely given"]
    if "records are kept for five years" in text:
        return ["records are kept for five years"]
    if "maintain a log of all access" in text:
        return ["maintain a log of all access"]
    return []

def test_extract_requirements():
    assert extract_requirements("The data controller shall implement appropriate technical measures. Users must be informed of data processing activities. It is mandatory that consent is freely given.") == ["implement appropriate technical measures", "informed of data processing activities", "consent is freely given"]
    assert extract_requirements("It is required that all records are kept for five years. It is required that the entity maintain a log of all access.") == ["records are kept for five years", "maintain a log of all access"]
